python3 -c "
import json, sys, os, re
data = json.load(sys.stdin)
path = data.get('tool_input', {}).get('file_path', '')
basename = os.path.basename(path)

security_files = [
  'auth.middleware.ts', 'auth.service.ts', 'auth.repository.ts',
  'auth.routes.ts', 'rateLimiter.middleware.ts'
]

infra_files = [
  'docker-compose.yml', 'docker-compose.yaml', '.env', '.env.example',
  '.env.local', '.env.production', '.env.development'
]

if basename in security_files:
  print(json.dumps({
    'hookSpecificOutput': {
      'hookEventName': 'PreToolUse',
      'permissionDecision': 'deny',
      'permissionDecisionReason': f'BLOCKED: {basename} is a security-sensitive file. Changes to auth/security files must be reviewed and applied manually. Claude can only suggest changes — do not edit this file directly.'
    }
  }))
  sys.exit(0)

if basename in infra_files or path.endswith('.env') or '/.github/' in path or path.startswith('.github/'):
  print(json.dumps({
    'hookSpecificOutput': {
      'hookEventName': 'PreToolUse',
      'permissionDecision': 'deny',
      'permissionDecisionReason': f'BLOCKED: {basename} is an infrastructure config file. Changes to docker-compose, .env, and CI files must be applied manually. Claude can only recommend changes.'
    }
  }))
  sys.exit(0)

migration_pattern = re.compile(r'/migrations/[^/]+\.(ts|js)$')
if migration_pattern.search(path):
  print(json.dumps({
    'hookSpecificOutput': {
      'hookEventName': 'PreToolUse',
      'permissionDecision': 'deny',
      'permissionDecisionReason': f'BLOCKED: Migration files must be reviewed before running. Apply changes manually and run yarn workspace backend migrate only after verifying the SQL it generates.'
    }
  }))
  sys.exit(0)
"

python3 -c "
import json, sys, re
data = json.load(sys.stdin)
cmd = data.get('tool_input', {}).get('command', '')

destructive = re.compile(
  r'\b(DELETE\s+FROM|DROP\s+TABLE|DROP\s+DATABASE|DROP\s+SCHEMA|TRUNCATE\s+TABLE|TRUNCATE)\b',
  re.IGNORECASE
)

if destructive.search(cmd):
  print(json.dumps({
    'hookSpecificOutput': {
      'hookEventName': 'PreToolUse',
      'permissionDecision': 'deny',
      'permissionDecisionReason': 'BLOCKED: Destructive SQL detected (DELETE/DROP/TRUNCATE). Claude is not permitted to delete data or drop tables. Run this command manually after verifying it is safe.'
    }
  }))
"
